sed -i "s/const \[downloadedApps, setDownloadedApps\] = useState<Set<string>>(new Set());/const [downloadedApps, setDownloadedApps] = useState<Set<string>>(() => {\n    const saved = localStorage.getItem('ios_store_downloaded_apps');\n    return saved ? new Set(JSON.parse(saved)) : new Set();\n  });\n\n  useEffect(() => {\n    localStorage.setItem('ios_store_downloaded_apps', JSON.stringify(Array.from(downloadedApps)));\n  }, [downloadedApps]);/g" src/App.tsx
